head.script:
scwin.vCurDate = "";
scwin.strCurDay  = "";
scwin.strCurTime = "";
scwin.weekday = "";

// 세션정보 가져오기
scwin.memJson    = $c.data.getMemInfo();

scwin.userClsCd  = scwin.memJson.userClsCd;
scwin.sysAdminYn = scwin.memJson.sysAdminYn;
scwin.loginId    = scwin.memJson.userId;
scwin.clntNo     = scwin.memJson.clntNo;
scwin.clntNm     = scwin.memJson.clntNm;

scwin.gv_crryoutEdiType = "";
scwin.gv_crryinEdiType  = "";
scwin.param_gubun       = "";
scwin.crryoutEdiType    = "";
scwin.crryinEdiType     = "";

scwin.loUpperLobranCd = $c.data.getMemInfo("loUpperLobranCd");

//현재시간 조회
scwin.f_getTime = function(){
    scwin.vCurDate = $c.date.getServerDateTime();
    scwin.strCurDay  = scwin.vCurDate.substring(0, 8);
    scwin.strCurTime = scwin.vCurDate.substring(8);

    scwin.weekday = $c.date.getDay(scwin.vCurDate, "num");
}
//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload =  function() {

    scwin.params = $c.data.getParameter();

    console.log("#### 21p scwin.params : "+Object.keys(scwin.params).length+"<<< #### >>>"+JSON.stringify(scwin.params));

    //공통코드 적용()
    const codeOptions = [ 
        { grpCd : "OP678", compID : "lc_hndlCdOut,lc_hndlCdIn"}, //F/E
    ];

    $c.data.setCommonCode(codeOptions);

    //DsConstants.CRRYINOUT_EDI_COPI_CODECO (COPI_CODECO) = CD / (COPINO) = CO
    scwin.crryoutEdiType = scwin.params.crryoutEdiType;
    scwin.crryinEdiType  = scwin.params.crryinEdiType;

    //반출(COPINO)
    if (DsConstants.CRRYINOUT_EDI_COPI_CODECO == scwin.crryoutEdiType) {
        tb_crryOutCopinoAll.show("none");
    }
    else {
        tb_crryOutCopinoAll.show("inline");
        grp_crryCopiCodeco.hide();
    }

    //반출(COPI_CODECO)
    if (DsConstants.CRRYINOUT_EDI_COPI_CODECO == scwin.crryoutEdiType) {
        tb_crryOutCopiCodecoAll.show("inline");
    }
    else {
        tb_crryOutCopiCodecoAll.show("none");
    }

    //반입(COPINO)
    if (DsConstants.CRRYINOUT_EDI_COPI_CODECO == scwin.crryinEdiType) {
        tb_crryInCopinoAll.hide();
    }
    else {
        tb_crryInCopinoAll.show();
        grp_crryCopiCodeco.hide();
    }

    //반입(COPI_CODECO)
    if (DsConstants.CRRYINOUT_EDI_COPI_CODECO == scwin.crryinEdiType) {
        tb_crryInCopiCodecoAll.show("inline");
    }
    else {
        tb_crryInCopiCodecoAll.show("none");
    }

    if( Object.keys(scwin.params).length > 0 ) {
        em_odrNo.setValue        (scwin.params.arrParam[0][ 2]);
        em_wrkStDt.setValue      (scwin.params.arrParam[0][ 9]);
        em_wrkEndDt.setValue     (scwin.params.arrParam[0][10]);
        em_cntrNo.setValue       (scwin.params.arrParam[0][11]);
        em_dptWrkPlCd.setValue   (scwin.params.arrParam[0][12]);
        em_arvWrkPlCd.setValue   (scwin.params.arrParam[0][13]);
        txt_dptWrkPlNm.setValue  (scwin.params.arrParam[0][14]);
        txt_arvWrkPlNm.setValue  (scwin.params.arrParam[0][15]);

        scwin.gv_crryoutEdiType = scwin.params.arrParam[0][16];
        scwin.gv_crryinEdiType  = scwin.params.arrParam[0][17];
        scwin.param_gubun       = scwin.params.arrParam[0][18];

        scwin.f_Retrieve();
    } else {
        $c.win.alert("EDI정보를 가져오지 못했습니다");
        return false;
    }

    $c.gus.cfDisableObjects([tb_srchCond]);

    if( scwin.loginId == "001249" || scwin.loginId == "021270" || scwin.loginId == "030428"
        || scwin.loginId == "100423" || scwin.loginId == "140814" || scwin.loginId == "zampion"
        || scwin.loginId == "areum" ) 
    {
        $c.gus.cfDisableObjects([chk_bondTransYn, ed_bondYardCd, txt_bondYardNm]);
    }

    if( scwin.userClsCd == "05" ) {
        $c.gus.cfDisableObjects([lc_bondTransVehclYn1,lc_bondTransVehclYn2]);
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function() {

    dma_search.set("qryClsCd"           , scwin.params.arrParam[0][ 0]);
    dma_search.set("transWrkIndictNo"   , scwin.params.arrParam[0][ 1]);
    dma_search.set("odrNo"              , scwin.params.arrParam[0][ 2]);
    dma_search.set("cntrSeq"            , scwin.params.arrParam[0][ 3]);
    dma_search.set("wrkPathSeq"         , scwin.params.arrParam[0][ 4]);
    dma_search.set("wrkStpSeq"          , scwin.params.arrParam[0][ 5]);

    dma_search.set("crryoutDt"          , em_wrkStDt.getValue()   );
    dma_search.set("crryinDt"           , em_wrkEndDt.getValue()  );
    dma_search.set("cntrNo"             , em_cntrNo.getValue()    );
    dma_search.set("dptWrkPlCd"         , em_dptWrkPlCd.getValue());
    dma_search.set("arvWrkPlCd"         , em_arvWrkPlCd.getValue());

    dma_search.set("crryoutEdiType"     , scwin.gv_crryoutEdiType);
    dma_search.set("crryinEdiType"      , scwin.gv_crryinEdiType);

    dma_search.set("vehclNo"            , scwin.params.arrParam[0][ 7]);
    dma_search.set("vehclIdCardNo"      , scwin.params.arrParam[0][ 8]);

    //console.log("##### scwin.params.arr1 : "+JSON.stringify(scwin.params.arr1)+" :: "+scwin.params.arr1.constructor+" :: "+Object.keys(scwin.params.arr1).length);

    //반출입에서 호출하는경우
    if (scwin.params.arrParam[0][ 0] == "1") {
        if (scwin.params.arrParam[1].length > 0) {
            dma_search.set("transWrkIndictNo"   , scwin.params.arrParam[1][ 0]);
            dma_search.set("vehclNo"            , scwin.params.arrParam[1][ 1]);
            dma_search.set("vehclIdCardNo"      , scwin.params.arrParam[1][ 2]);
            dma_search.set("drvNm"              , scwin.params.arrParam[1][ 3]);
            dma_search.set("cntctPl"            , scwin.params.arrParam[1][ 4]);
            dma_search.set("crryoutDt"          , scwin.params.arrParam[1][ 5]);
            dma_search.set("crryoutHh"          , scwin.params.arrParam[1][ 6]);
            dma_search.set("crryinDt"           , scwin.params.arrParam[1][ 7]);
            dma_search.set("crryinHh"           , scwin.params.arrParam[1][ 8]);
            dma_search.set("vehclShortCd"       , scwin.params.arrParam[1][ 9]);
            dma_search.set("eqCd"               , scwin.params.arrParam[1][10]);
        }
    }

    console.log("##### scwin.f_Retrieve");
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    //console.log("##### sbm_retrieve_submitdone : "+JSON.stringify(e));
    if (e.responseJSON.resultDataSet[0].Code < 0) return; 

    if( scwin.param_gubun == "NO" ) {
        $c.gus.cfDisableObjects([em_cntrNo,em_cntrNo2]);
    }
};

//-------------------------------------------------------------------------
// bind dataset
//-------------------------------------------------------------------------
scwin.f_bindDataset = function() {
    if(!$c.gus.cfIsNull(dma_resultsCopino1.get("odrNo"))) {
        dma_resultsCopino1.set("emcTransCoId" , "DBEXC050");
        dma_resultsCopino1.set("dpctTransCoId", "DBEXC050");
    }

    if(!$c.gus.cfIsNull(dma_resultsCopino2.get("odrNo"))) {
        if ($c.gus.cfIsNull(txt_mchtNm2.getValue())) {
            dma_resultsCopino2.set("mchtNm", em_mchtNmIn.getValue());
        }
        dma_resultsCopino2.set("emcTransCoId" , "DBEXC050");
        dma_resultsCopino2.set("dpctTransCoId", "DBEXC050");
    }

    if (!$c.gus.cfIsNull(dma_resultsCopiCodeco1.get("odrNo"))) {
        if(dma_resultsCopiCodeco1.get("cls") == "DT") {
            dma_resultsCopiCodeco1.set("blNo", em_blNo31.getValue());                       //화물관리번호
        } else {
            dma_resultsCopiCodeco1.set("blNo", em_blNo3.getValue());                        //B/L NO
        }
    }

    if (!$c.gus.cfIsNull(dma_resultsCopiCodeco2.get("odrNo"))) {
        if(dma_resultsCopiCodeco2.get("cls") == "DT") {
            dma_resultsCopiCodeco2.set("blNo", em_blNo41.getValue());                       //화물관리번호
        } else {
            dma_resultsCopiCodeco2.set("blNo", em_blNo4.getValue());                        //B/L NO
        }
    }
}

//-------------------------------------------------------------------------
// 필수값체크
//-------------------------------------------------------------------------
scwin.f_validate = async function() {

    //반출(COPINO)
    if (chk_crryOutCopino.getValue() == "T") {

        if (!await $c.gus.cfValidate([tb_crryOutCopino], null, true)) {

            return false;
        }

        //[사전정보그룹구분=터미널]이면 차량ID를 입력받아야함
        if (dma_resultsCopino1.get("preInfoGrpClsCd") == DsConstants.EDI_GRPCD_TM 
            && dma_resultsCopino1.get("vehclIdCardNo") == "") {

            await $c.gus.cfAlertMsg("[사전정보그룹구분]이 터미널 일때 [차량ID카드번호]는 필수입니다");
            return false;
        }

        //[full/empty구분=full]이면 SEAL NO를 입력받아야함
        if (dma_resultsCopino1.get("fullEmptyClsCd") == DsConstants.EDI_FULL_EMPTY_CLS_FULL
            && dma_resultsCopino1.get("sealNo") == "") {

            await $c.gus.cfAlertMsg("[E/F 구분]이 FULL 일때 [SEAL NO]는 필수입니다");
            return false;
        }

        // var v_features = "copyHeader=yes,rowFrom=1,rowCnt=1";
        // $c.gus.cfCopyDataSet(dma_resultsCopino1, ds_resultsCopino3, v_features);
        ds_resultsCopino3.insertRow();
        ds_resultsCopino3.setRowJSON(0, dma_resultsCopino1.getJSON());
    }

    //반입(COPINO)
    if (chk_crryInCopino.getValue() == "T") {
        if (!await $c.gus.cfValidate([tb_crryInCopino], null, true)) {

            return false;
        }

        if (dma_resultsCopino2.get("fullEmptyClsCd") == DsConstants.EDI_FULL_EMPTY_CLS_FULL 
            && (dma_resultsCopino2.get("totWt") == 0 || dma_resultsCopino2.get("totWt") == "")) {

            await $c.gus.cfAlertMsg("[E/F 구분]이 FULL 일때 [WEIGHT]는 필수입니다");
            return false;
        }

        //[사전정보그룹구분=터미널]이면 차량ID를 입력받아야함
        if (dma_resultsCopino2.get("preInfoGrpClsCd") == DsConstants.EDI_GRPCD_TM
            && dma_resultsCopino2.get("vehclIdCardNo") == "") {

            await $c.gus.cfAlertMsg("[사전정보그룹구분]이 터미널 일때 [차량ID카드번호]는 필수입니다");
            return false;
        }

        //[사전정보그룹구분=터미널]이면 모선/항차를 입력받아야함
        if (dma_resultsCopino2.get("preInfoGrpClsCd") == DsConstants.EDI_GRPCD_TM
            && dma_resultsCopino2.get("tmlVsslPortcnt") == "") {

            await $c.gus.cfAlertMsg("[사전정보그룹구분]이 터미널 일때 [모선/항차]는 필수입니다");
            return false;
        }

        //[full/empty구분=full]이면 SEAL NO를 입력받아야함
        if (dma_resultsCopino2.get("fullEmptyClsCd") == DsConstants.EDI_FULL_EMPTY_CLS_FULL
            && dma_resultsCopino2.get("sealNo") == "") {

            await $c.gus.cfAlertMsg("[E/F 구분]이 FULL 일때 [SEAL NO]는 필수입니다");
            return false;
        }

        //[full/empty구분=full]이고 SIZE/TYPE이 RF,RH 이면 냉동온도를 입력받아야함
        if (dma_resultsCopino2.get("fullEmptyClsCd") == DsConstants.EDI_FULL_EMPTY_CLS_FULL
                && em_frzTemper2.getValue() ==""
                && (dma_resultsCopino2.get("sizTyp")== "2232" || dma_resultsCopino2.get("sizTyp")== "4332" 
                    || dma_resultsCopino2.get("sizTyp")== "4337" || dma_resultsCopino2.get("sizTyp")== "4532")) 
            {
                if (!await $c.win.confirm("냉동컨테이너에 온도가 입력되지 않았습니다.\n그래도 계속 진행하시겠습니까?")) {
                    return false;
                }
            }

        // var v_features = "copyHeader=yes,rowFrom=1,rowCnt=1";
        // $c.gus.cfCopyDataSet(dma_resultsCopino2, ds_resultsCopino4, v_features);
        ds_resultsCopino4.insertRow();
        ds_resultsCopino4.setRowJSON(0, dma_resultsCopino2.getJSON());

        //PCY     
        if(scwin.param_gubun == "NO"){

            if(dma_resultsCopino2.get("bookingNo") == "" 
                && dma_resultsCopino2.get("blNo")== ""){

                await $c.gus.cfAlertMsg("수입은 B/L번호 , 수출은 BOOKING번호  필수입니다!!"); 
                return false;
            }    
        }                    
    }

    // 반출(COPI_CODECO)
    if (chk_crryOutCopiCodeco.getValue() == "T") {
        if (!await $c.gus.cfValidate([tb_crryOutCopiCodeco], null, true)) {

            return false;
        }

        //대한통운 일경우 컨테이너번호 필수
        if(dma_resultsCopiCodeco1.get("cls") == "DT") {

            if($c.gus.cfIsNull( dma_resultsCopiCodeco1.get("cntrNo") )) {

                await $c.gus.cfAlertMsg("작업지역이 [대한통운] 일경우 [컨테이너번호]는 필수 입니다.");
                return false;
            }
        }

        // var v_features = "copyHeader=yes,rowFrom=1,rowCnt=1";
        // $c.gus.cfCopyDataSet(ds_resultsCopiCodeco1, ds_resultsCopiCodeco3, v_features);

        // dma_resultsCopino1.setJSON(ds_resultsCopiCodeco3.getRowJSON(1));
        ds_resultsCopiCodeco3.insertRow();
        ds_resultsCopiCodeco3.setRowJSON(0, dma_resultsCopiCodeco3.getJSON());
    }

    //반입(COPI_CODECO)
    if (chk_crryInCopiCodeco.getValue() == "T") {

        if (!await $c.gus.cfValidate([tb_crryInCopiCodeco], null, true)) {
            return false;
        }

        //대한통운 일경우 컨테이너번호 필수
        if(dma_resultsCopiCodeco2.get("cls") == "DT") {

            if($c.gus.cfIsNull( dma_resultsCopiCodeco2.get("cntrNo") )) {

                await $c.gus.cfAlertMsg("작업지역이 [대한통운] 일경우 [컨테이너번호]는 필수 입니다.");
                return false;
            }
        }

        // var v_features = "copyHeader=yes,rowFrom=1,rowCnt=1";
        // $c.gus.cfCopyDataSet(ds_resultsCopiCodeco2, ds_resultsCopiCodeco4, v_features);
        ds_resultsCopiCodeco4.insertRow();
        ds_resultsCopiCodeco4.setRowJSON(0, dma_resultsCopiCodeco2.getJSON());
    }

    return true;
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.btn_save_onclick = function (e) {
    scwin.f_save();
};

scwin.f_save = async function(){
    //윤동진대리님 요청사항
    //내부사용자가 아니면 평일 17시 30분이후 KBCTCY 주말 12시이후 KBCTCY 전송불가
    //박재율 대리님 요청으로 17이 이후 전송못하도록 수정 20150116

    //현재시간가져온다.
    scwin.f_getTime();

    if(em_dptWrkPlCd.getValue() == "6C01" || em_arvWrkPlCd.getValue() == "6C01" ){
        if(scwin.userClsCd != "01") {	//사용자구분코드 01:그룹사가 아니면)
            if(scwin.weekday == "SUN" || scwin.weekday == "SAT"){ // 주말 12시이후 전송안됨

                await $c.gus.cfAlertMsg("주말에는 COPINO전송을 하실수 없습니다. \n 문의 사항은 담당 배차에게 문의주세요.");
                return false; 

            } else {// 평일 17시 30분 이후 전송안됨

                if(scwin.strCurTime > "1730" ){
                    await $c.gus.cfAlertMsg("17시 30분 이후에는 KBCTCY의 요청으로 EDI 전송을 할 수 없습니다.");
                    return false; 
                }
            }
        }    
    }

    if ($c.gus.cfIsNull(dma_resultsCopino1.get("odrNo")) && $c.gus.cfIsNull(dma_resultsCopino2.get("odrNo"))
            && $c.gus.cfIsNull(dma_resultsCopiCodeco1.get("odrNo")) && $c.gus.cfIsNull(dma_resultsCopiCodeco2.get("odrNo")))
    {

        await $c.gus.cfAlertMsg("저장할 데이터가 없습니다");
        return;
    }

    scwin.f_bindDataset();

    //황창기20141127 코피노 전송시  수입 프리즘선사는 DO넘버 필수값체크함  'SIT', 'STI', 'SITC', 'NOLS', 'DWS', 'TCLC', 'TCL', 'SOFC', 'SFL', 'TMSC', 'TMS', 'SKR', 'GBH', 'KWS', 'ESL'
    if(em_odrNo.getValue().substring(1,3)=="C2" && (dma_resultsCopino1.get("shpCoCd") == "SIT" || dma_resultsCopino1.get("shpCoCd") == "STI" ||
                                                dma_resultsCopino1.get("shpCoCd") == "SITC" || dma_resultsCopino1.get("shpCoCd") == "NOLS" ||
                                                dma_resultsCopino1.get("shpCoCd") == "DWS" || dma_resultsCopino1.get("shpCoCd") == "TCLC" ||
                                                dma_resultsCopino1.get("shpCoCd") == "TCL" || dma_resultsCopino1.get("shpCoCd") == "SOFC" ||
                                                dma_resultsCopino1.get("shpCoCd") == "SFL" || dma_resultsCopino1.get("shpCoCd") == "TMSC"||
                                                dma_resultsCopino1.get("shpCoCd") == "TMS" || dma_resultsCopino1.get("shpCoCd") == "SKR"||
                                                dma_resultsCopino1.get("shpCoCd") == "GBH" || dma_resultsCopino1.get("shpCoCd") == "KWS"||
                                                dma_resultsCopino1.get("shpCoCd") == "MOL" ||
                                                dma_resultsCopino1.get("shpCoCd") == "ESL")
    ){
        if($c.gus.cfIsNull(dma_resultsCopino1.get("doNo"))){
            await $c.gus.cfAlertMsg("프리즘선사 수입 반입/반출 코피노 전송시  \n D/O NO 는 필수입력값입니다.");
            em_doNo1.focus();
            return false;
        }
    }

    if(em_odrNo.getValue().substring(1,3)=="C2" && (dma_resultsCopino2.get("shpCoCd") == "SIT" || dma_resultsCopino2.get("shpCoCd") == "STI" ||
                                                dma_resultsCopino2.get("shpCoCd") == "SITC" || dma_resultsCopino2.get("shpCoCd") == "NOLS" ||
                                                dma_resultsCopino2.get("shpCoCd") == "DWS" || dma_resultsCopino2.get("shpCoCd") == "TCLC" ||
                                                dma_resultsCopino2.get("shpCoCd") == "TCL" || dma_resultsCopino2.get("shpCoCd") == "SOFC" ||
                                                dma_resultsCopino2.get("shpCoCd") == "SFL" || dma_resultsCopino2.get("shpCoCd") == "TMSC"||
                                                dma_resultsCopino2.get("shpCoCd") == "TMS" || dma_resultsCopino2.get("shpCoCd") == "SKR"||
                                                dma_resultsCopino2.get("shpCoCd") == "GBH" || dma_resultsCopino2.get("shpCoCd") == "KWS"|| 
                                                dma_resultsCopino2.get("shpCoCd") == "MOL" || 
                                                dma_resultsCopino2.get("shpCoCd") == "ESL")
    ){
        if($c.gus.cfIsNull(dma_resultsCopino2.get("doNo"))){
            await $c.gus.cfAlertMsg("프리즘선사 수입 반입/반출 코피노 전송시  \n D/O NO 는 필수입력값입니다.");
            em_doNo2.focus();
            return false;
        }
    }

    if (!await scwin.f_validate()) {

        return;
    }

    if (ds_resultsCopino3.getRowCount() == 0 && ds_resultsCopino4.getRowCount() ==0
            && ds_resultsCopiCodeco3.getRowCount() == 0 && ds_resultsCopiCodeco4.getRowCount() == 0) {

        await $c.gus.cfAlertMsg("저장할 데이터가 없습니다");
        return;
    }

    //반출
    if( ds_resultsCopino3.getRowCount() > 0 ) {

        //전송구분코드 : 전송(0) 추후전송(3)
        if (ds_resultsCopino3.getCellData(0, "docStsCls") == "") {

            //문서상태코드 : 원본(9) 수정본(4) 삭제본(3)
            ds_resultsCopino3.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_ORIG);
        }

        if ( ds_resultsCopino3.getCellData(0, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_COMPLETE ) {

            ds_resultsCopino3.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_CHG);
        }

        ds_resultsCopino3.setCellData(0, "sndClsCd", DsConstants.EDI_SND_CLS_CD_LATER_SND);
    }

    //반입
    if( ds_resultsCopino4.getRowCount() > 0 ) {
        //전송구분코드 : 전송(0) 추후전송(3)
        if (ds_resultsCopino4.getCellData(0, "docStsCls") == "") {

            //문서상태코드 : 원본(9) 수정본(4) 삭제본(3)
            ds_resultsCopino4.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_ORIG);
        }

        if ( ds_resultsCopino4.getCellData(0, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_COMPLETE) {

            ds_resultsCopino4.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_CHG);
        }

        ds_resultsCopino4.setCellData(0, "sndClsCd", DsConstants.EDI_SND_CLS_CD_LATER_SND );
    }

    //반출
    if (ds_resultsCopiCodeco3.getRowCount() > 0) {

        //전송구분코드 : 전송(0) 추후전송(3)
        if (ds_resultsCopiCodeco3.getCellData(0, "docStsCls") == "") {

            //문서상태코드 : 원본(9) 수정본(4) 삭제본(3)
            ds_resultsCopiCodeco3.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_ORIG );
        }

        if ( ds_resultsCopiCodeco3.getCellData(0, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_COMPLETE ) {

            ds_resultsCopiCodeco3.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_CHG);
        }

        ds_resultsCopiCodeco3.setCellData(0, "sndClsCd", DsConstants.EDI_SND_CLS_CD_LATER_SND);
    }

    //반입
    if (ds_resultsCopiCodeco4.getRowCount() > 0) {

        //전송구분코드 : 전송(0) 추후전송(3)
        if (ds_resultsCopiCodeco4.getCellData(0, "docStsCls") == "") {

            //문서상태코드 : 원본(9) 수정본(4) 삭제본(3)
            ds_resultsCopiCodeco4.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_ORIG);
        }

        if ( ds_resultsCopiCodeco4.getCellData(0, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_COMPLETE ) {

            ds_resultsCopiCodeco4.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_CHG);
        }

        ds_resultsCopiCodeco4.setCellData(0, "sndClsCd", DsConstants.EDI_SND_CLS_CD_LATER_SND);
    }


    if( scwin.userClsCd == "05" && scwin.strCurTime > "1730" && em_dptWrkPlCd.getValue() == "6C01") {

        await $c.win.alert("17시 30분 이후에는 KBCT CY의 요청으로 EDI 전송을 할 수 없습니다. KBCT CY에 문의하세요");
        return false;
    }

    if (await $c.win.confirm("저장하시겠습니까?")) {

        $c.sbm.execute(sbm_save);
    } else {
        ds_resultsCopino3.removeAll();
        ds_resultsCopino4.removeAll();
        ds_resultsCopiCodeco3.removeAll();
        ds_resultsCopiCodeco4.removeAll();
    }
}

