//-------------------------------------------------------------------------
// 전송
//-------------------------------------------------------------------------
scwin.f_transfer = async function(){
    	//윤동진대리님 요청사항
		//내부사용자가 아니면 평일 17시 30분 이후 KBCTCY 주말 12시이후 KBCTCY 전송불가
		//박재율 대리님 요청으로 17이 이후 전송못하도록 수정 20150116

	    //현재시간가져온다.
	    scwin.f_getTime();   

	    if(em_dptWrkPlCd.getValue() == "6C01" || em_arvWrkPlCd.getValue() == "6C01" ){
		    if(scwin.userClsCd != "01") {	//사용자구분코드 01:그룹사가 아니면)
				if(scwin.weekday == "SUN" || scwin.weekday == "SAT"){ // 주말 12시이후 전송안됨
				    await $c.gus.cfAlertMsg("주말에는 COPINO전송을 하실수 없습니다. \n 문의 사항은 담당 배차에게 문의주세요.");
					return false; 
			    }else{// 평일 17시 30분 이후 전송안됨
				    if(scwin.currTime > "1730"){				    	
				    	await $c.gus.cfAlertMsg("17시 30분 이후에는 KBCTCY의 요청으로 EDI 전송을 할 수 없습니다.");
					    return false; 
				    }
			    }
		    }    
	    }

        if ($c.gus.cfIsNull(dma_resultsCopino1.get("odrNo") ) 
                && $c.gus.cfIsNull(dma_resultsCopino2.get("odrNo") )
                && $c.gus.cfIsNull(dma_resultsCopiCodeco1.get("odrNo") )
                && $c.gus.cfIsNull(dma_resultsCopiCodeco2.get("odrNo") )) {

            await $c.gus.cfAlertMsg("전송할 데이터가 없습니다");
            return;
        }

        scwin.f_bindDataset();

        //황창기20141127 코피노 전송시  수입 프리즘선사는 DO넘버 필수값체크함  'SIT', 'STI', 'SITC', 'NOLS', 'DWS', 'TCLC', 'TCL', 'SOFC', 'SFL', 'TMSC', 'TMS', 'SKR', 'GBH', 'KWS', 'ESL'
        if(em_odrNo.getValue().substring(1,3)=="C2" && (dma_resultsCopino1.get("shpCoCd") == "SIT" || dma_resultsCopino1.get("shpCoCd") == "STI" ||
                                                    dma_resultsCopino1.get("shpCoCd") == "SITC" || dma_resultsCopino1.get("shpCoCd") == "NOLS" ||
                                                    dma_resultsCopino1.get("shpCoCd") == "DWS" || dma_resultsCopino1.get("shpCoCd") == "TCLC" ||
                                                    dma_resultsCopino1.get("shpCoCd") == "TCL" || dma_resultsCopino1.get("shpCoCd") == "SOFC" ||
                                                    dma_resultsCopino1.get("shpCoCd") == "SFL" || dma_resultsCopino1.get("shpCoCd") == "TMSC"||
                                                    dma_resultsCopino1.get("shpCoCd") == "TMS" || dma_resultsCopino1.get("shpCoCd") == "SKR"||
                                                    dma_resultsCopino1.get("shpCoCd") == "GBH" || dma_resultsCopino1.get("shpCoCd") == "KWS"||
                                                    dma_resultsCopino1.get("shpCoCd") == "MOL" ||
                                                    dma_resultsCopino1.get("shpCoCd") == "ESL")
        ){
            if($c.gus.cfIsNull(dma_resultsCopino1.get("doNo"))){
                await $c.gus.cfAlertMsg("프리즘선사 수입 반입/반출 코피노 전송시  \n D/O NO 는 필수입력값입니다.");
                em_doNo1.focus();
                return false;
            }
        }

        if(em_odrNo.getValue().substring(1,3)=="C2" && (dma_resultsCopino2.get("shpCoCd") == "SIT"    || dma_resultsCopino2.get("shpCoCd") == "STI" ||
                                                    dma_resultsCopino2.get("shpCoCd") == "SITC" || dma_resultsCopino2.get("shpCoCd") == "NOLS" ||
                                                    dma_resultsCopino2.get("shpCoCd") == "DWS"  || dma_resultsCopino2.get("shpCoCd") == "TCLC" ||
                                                    dma_resultsCopino2.get("shpCoCd") == "TCL"  || dma_resultsCopino2.get("shpCoCd") == "SOFC" ||
                                                    dma_resultsCopino2.get("shpCoCd") == "SFL"  || dma_resultsCopino2.get("shpCoCd") == "TMSC"||
                                                    dma_resultsCopino2.get("shpCoCd") == "TMS"  || dma_resultsCopino2.get("shpCoCd") == "SKR"||
                                                    dma_resultsCopino2.get("shpCoCd") == "GBH"  || dma_resultsCopino2.get("shpCoCd") == "KWS"|| 
                                                    dma_resultsCopino2.get("shpCoCd") == "MOL"|| 
                                                    dma_resultsCopino2.get("shpCoCd") == "ESL")
        ){
            if($c.gus.cfIsNull(dma_resultsCopino2.get("doNo"))){
                await $c.gus.cfAlertMsg("프리즘선사 수입 반입/반출 코피노 전송시  \n D/O NO 는 필수입력값입니다.");
                em_doNo2.focus();
                return false;
            }
        }

        if (!await scwin.f_validate()) {

            return;
        }

        if (ds_resultsCopino3.getRowCount() == 0 && ds_resultsCopino4.getRowCount() == 0
                && ds_resultsCopiCodeco3.getRowCount() == 0 && ds_resultsCopiCodeco4.getRowCount() == 0) {

            await $c.gus.cfAlertMsg("저장할 데이터가 없습니다");
            return;
        }

        //--------------------------------------------------------
        //반출
        //--------------------------------------------------------
        if(ds_resultsCopino3.getRowCount() > 0){

            //전송구분코드 : 전송(0) 추후전송(3)
            if (ds_resultsCopino3.getCellData(0, "docStsCls") == "") {

                //문서상태코드 : 원본(9) 수정본(4) 삭제본(3)
                ds_resultsCopino3.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_ORIG );
            }

            if ( ds_resultsCopino3.getCellData(0, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_COMPLETE ) {

                ds_resultsCopino3.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_CHG );
            }

            ds_resultsCopino3.setCellData(0, "sndClsCd", DsConstants.EDI_SND_CLS_CD_SND_WAIT );
        }

        //--------------------------------------------------------
        //반입
        //--------------------------------------------------------
        if(ds_resultsCopino4.getRowCount() > 0){

            //전송구분코드 : 전송(0) 추후전송(3)
            if (ds_resultsCopino4.getCellData(0, "docStsCls") == "") {

                //문서상태코드 : 원본(9) 수정본(4) 삭제본(3)
                ds_resultsCopino4.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_ORIG);
            }

            if ( ds_resultsCopino4.getCellData(0, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_COMPLETE ) {

                ds_resultsCopino4.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_CHG );
            }

            ds_resultsCopino4.setCellData(0, "sndClsCd", DsConstants.EDI_SND_CLS_CD_SND_WAIT );
        }

        //--------------------------------------------------------
        //반출
        //--------------------------------------------------------
        if(ds_resultsCopiCodeco3.getRowCount() > 0) {

            //전송구분코드 : 전송(0) 추후전송(3)
            if (ds_resultsCopiCodeco3.getCellData(0, "docStsCls") == "") {

                //문서상태코드 : 원본(9) 수정본(4) 삭제본(3)
                ds_resultsCopiCodeco3.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_ORIG );
            }

            if ( ds_resultsCopiCodeco3.getCellData(0, "sndClsCd", DsConstants.EDI_SND_CLS_CD_SND_COMPLETE )) {

                ds_resultsCopiCodeco3.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_CHG );
            }

            ds_resultsCopiCodeco3.setCellData(0, "sndClsCd", DsConstants.EDI_SND_CLS_CD_SND_WAIT );
        }

        //--------------------------------------------------------
        //반입
        //--------------------------------------------------------
        if(ds_resultsCopiCodeco4.getRowCount() > 0) {

            //전송구분코드 : 전송(0) 추후전송(3)
            if (ds_resultsCopiCodeco4.getCellData(0, "docStsCls") == "") {

                //문서상태코드 : 원본(9) 수정본(4) 삭제본(3)
                ds_resultsCopiCodeco4.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_ORIG );
            }

            if ( ds_resultsCopiCodeco4.getCellData(0, "sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_COMPLETE ) {

                ds_resultsCopiCodeco4.setCellData(0, "docStsCls", DsConstants.EDI_DOC_STS_CLS_CHG );
            }

            ds_resultsCopiCodeco4.setCellData(0, "sndClsCd", DsConstants.EDI_SND_CLS_CD_SND_WAIT );
        }


        if( scwin.userClsCd == "05" && scwin.strCurTime > "1730" && em_dptWrkPlCd.getValue() == "6C01") {

            $c.win.alert("17시 30분 이후에는 KBCT CY의 요청으로 EDI 전송을 할 수 없습니다. KBCT CY에 문의하세요");
            return false;
        }


        if (await $c.win.confirm("전송하시겠습니까?")) {

            $c.sbm.execute(sbm_send);

        } else {
            ds_resultsCopino3.removeAll()
            ds_resultsCopino4.removeAll();
            ds_resultsCopiCodeco3.removeAll();
            ds_resultsCopiCodeco4.removeAll();
        }
}

