scwin.f_disableCompCopiCodeco = function(gubun, inout) {

    if(gubun == "HY") {     //현대용당일경우
        //직상차여부, 철송주체, 철송요청일자, 철송요청시간, 진수화인, 착지, 화물관리번호
        if(inout == 1) {
            $c.gus.cfDisableObjects([lc_drtOnYn3, lc_railroadCore3, em_railroadReqDt3, lc_railroadReqHh3, em_consignee3, lc_arvRailroadPlc3, em_blNo31]);
        } else {
            $c.gus.cfDisableObjects([lc_drtOnYn4, lc_railroadCore4, em_railroadReqDt4, lc_railroadReqHh4, em_consignee4, lc_arvRailroadPlc4, em_blNo41]);
        }
    } else if(gubun == "DT") {  //대한통운일경우 
        //화주코드, 화주명, From DEPOT, From 지역,TO DEPOT, TO 지역, REMARK, 직상차여부, PTI여부,
        //철송주체, 철송요청일자, 철송요청시간, 진수화인, 착지, TS구분, 수출면장번호,
        //면장기일, BL번호
        if(inout == 1) {

            $c.gus.cfDisableObjects([img_mchtCd3, em_mchtCd3, txt_mchtNm3, em_dptDepot3, em_dptRgn3, em_arvDepot3, em_arvRgn3, em_unqItm3, lc_drtOnYn3, lc_transCls3,
                                lc_railroadCore3, img_railroadReqDt3, em_railroadReqDt3, lc_railroadReqHh3, em_consignee3, lc_arvRailroadPlc3, lc_tsCls3, em_expLicenseNo3,
                                img_licenseFdd3, em_licenseFdd3, em_blNo3]);
        } else {
            $c.gus.cfDisableObjects([img_mchtCd4, em_mchtCd4, txt_mchtNm4, em_dptDepot4, em_dptRgn4, em_arvDepot4, em_arvRgn4, em_unqItm4, lc_drtOnYn4, lc_transCls4,
                                lc_railroadCore4, img_railroadReqDt4, em_railroadReqDt4, lc_railroadReqHh4, em_consignee4, lc_arvRailroadPlc4, lc_tsCls4, em_expLicenseNo4,
                                img_licenseFdd4, em_licenseFdd4, em_blNo4]);
        }

    } else {        //현대경인일경우
        //직상차여부, TS구분, 수출면장번호, 화물관리번호
        if(inout == 1) {
            $c.gus.cfDisableObjects([lc_drtOnYn3, lc_tsCls3, em_expLicenseNo3, em_blNo31]);
        } else {
            $c.gus.cfDisableObjects([lc_drtOnYn4, lc_tsCls4, em_expLicenseNo4, em_blNo41]);
        }
    }
}

//-------------------------------------------------------------------------
// 전송여부 switch
//-------------------------------------------------------------------------
scwin.f_switchTransYn = function(gubun) {

    if (gubun == 1) {
        if (chk_crryOutCopino.getValue() == "T") {
            $c.gus.cfEnableObjects([tb_crryOutCopino]);
        } else {
            $c.gus.cfDisableObjects([tb_crryOutCopino]);
        }

    } else if (gubun == 2) {
        if (chk_crryInCopino.getValue() == "T") {
            $c.gus.cfEnableObjects([tb_crryInCopino]);
        } else {
            $c.gus.cfDisableObjects([tb_crryInCopino]);
        }

    } else if (gubun == 3) {
        if (chk_crryOutCopiCodeco.getValue() == "T") {
            $c.gus.cfEnableObjects([tb_crryOutCopiCodeco]);
            scwin.f_disableCompCopiCodeco(dma_resultsCopiCodeco1.get("cls"), 1);
        } else {
            $c.gus.cfDisableObjects([tb_crryOutCopiCodeco]);
        }

    } else if (gubun == 4) {
        if (chk_crryInCopiCodeco.getValue() == "T") {
            $c.gus.cfEnableObjects([tb_crryInCopiCodeco]);
            scwin.f_disableCompCopiCodeco(dma_resultsCopiCodeco2.get("cls"), 2);
        } else {
            $c.gus.cfDisableObjects([tb_crryInCopiCodeco]);
        }
    }

    //황창기 자가업체 보세운송차량여부 수정 불가하게 수정			  
    if(scwin.userClsCd == "05"){
        $c.gus.cfDisableObjects([lc_bondTransVehclYn1, lc_bondTransVehclYn2]);
    }
};

scwin.ds_resultsCopino_ondataload = function () {
    console.log("#### ds_resultsCopino_ondataload : "+ds_resultsCopino.getRowCount());

    if( ds_resultsCopino.getRowCount() == 0 ){
        //$c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }

    dma_resultsCopino1.setEmptyValue();
    dma_resultsCopino2.setEmptyValue();

    var v_bIsCrryOut = false;
    var v_bIsCrryIn  = false;

    for ( var i = 0; i < ds_resultsCopino.getRowCount(); i ++ ) {
        if( ds_resultsCopino.getCellData(i, "crryinCrryoutCls") == "1" ) {
            v_bIsCrryOut = true;
        }
        if( ds_resultsCopino.getCellData(i, "crryinCrryoutCls") == "2" ) {
            v_bIsCrryIn = true;
        }

        if( ds_resultsCopino.getCellData(i, "crryinCrryoutCls") == "1" ) {
            //반출
            dma_resultsCopino1.setJSON(ds_resultsCopino.getRowJSON(i));

            if( (dma_resultsCopino1.get("transDstFrom") == "6C29" || dma_resultsCopino1.get("transDstFrom") == "6P90" )
                && dma_resultsCopino1.get("cntrNo") == "") 
            {
                em_cntrNo1.setValue("M001");
            }
            else {

            }

            var sndDtHh = (dma_resultsCopino1.get("sndDt") == "" ? "" : $c.gus.cfGetFormatStr(dma_resultsCopino1.get("sndDt"), "####/##/##"))
                        + " "
                        + (dma_resultsCopino1.get("sndHh") == "" ? "" : $c.gus.cfGetFormatStr(dma_resultsCopino1.get("sndHh"), "##:##:##"))
                        ;
            td_sndDtHh1.setValue(sndDtHh);

            if( dma_resultsCopino1.get("transDstFrom") == "6C01" || dma_resultsCopino1.get("transDstFrom") == "6P13" 
             && dma_resultsCopino1.get("transDstTo") == "6C01" || dma_resultsCopino1.get("transDstTo") == "6P13" ) {
                lc_bondTransVehclYn1.setValue(dma_resultsCopino1.get("bondTransVehclYn"));
            }
            else {
                if( dma_resultsCopino1.get("sndClsCd") != DsConstants.EDI_SND_CLS_CD_SND_COMPLETE
                 && dma_resultsCopino1.get("sndClsCd") != DsConstants.EDI_SND_CLS_CD_LATER_SND
                 && dma_resultsCopino1.get("sndClsCd") != DsConstants.EDI_SND_CLS_CD_IMPITEM_WARN
                 && dma_resultsCopino1.get("sndClsCd") != DsConstants.EDI_SND_CLS_CD_SND_WAIT ) {
                    lc_bondTransVehclYn1.setValue("N");
                 }
                 else {
                    lc_bondTransVehclYn1.setValue(dma_resultsCopino1.get("bondTransVehclYn"));
                 }
            }

            lc_frtcarClsOut.setValue(dma_resultsCopino1.get("adminfrtcarYn"));

            if( dma_resultsCopino1.get("sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_COMPLETE ) {
                div_sndClsCd1.setValue("전송완료");
            }
            else if( dma_resultsCopino1.get("sndClsCd") == DsConstants.EDI_SND_CLS_CD_LATER_SND ) {
                div_sndClsCd1.setValue("사후전송");
            }
            else if( dma_resultsCopino1.get("sndClsCd") == DsConstants.EDI_SND_CLS_CD_IMPITEM_WARN ) {
                div_sndClsCd1.setValue("필수입력오류");
            }
            else if( dma_resultsCopino1.get("sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_WAIT ) {
                div_sndClsCd1.setValue("전송대기");
            }
            else {
                div_sndClsCd1.setValue("미등록");
            }

            if( dma_resultsCopino1.get("preInfoGrpClsCd") == DsConstants.EDI_GRPCD_KYUNGIN_ICD
             && dma_resultsCopino1.get("wrkStpCd") != DsConstants.WRK_STP_CD_RAILROAD ) {
                $c.gus.cfDisableObjects([em_vehclNoFrtcarNo1]);
            }

            if( $c.gus.cfIsNull(dma_resultsCopino1.get("copinoResponse"))) {
                lbl_copinoErr1.setValue("");
            }
            else {
                var tempStr = "<font color=blue>반출 COPINO 전송오류 내역 :</font> "
                            + "<font color=red>" + dma_resultsCopino1.get("copinoResponse") + "</font><br>";
                lbl_copinoErr1.setValue(tempStr);
            }
        }

        if( ds_resultsCopino.getCellData(i, "crryinCrryoutCls") == "2" ) {
            //반입
            dma_resultsCopino2.setJSON(ds_resultsCopino.getRowJSON(i));

            var sndDtHh = (dma_resultsCopino2.get("sndDt") == "" ? "" : $c.gus.cfGetFormatStr(dma_resultsCopino2.get("sndDt"), "####/##/##"))
                        + " "
                        + (dma_resultsCopino2.get("sndHh") == "" ? "" : $c.gus.cfGetFormatStr(dma_resultsCopino2.get("sndHh"), "##:##:##"))
                        ;
            td_sndDtHh2.setValue(sndDtHh);

            if( dma_resultsCopino2.get("transWrkIndictNo") == "" ) {
                em_transWrkIndictNo2.setValue(scwin.params.arr0.arrParam19);
            }

            if( dma_resultsCopino2.get("transDstFrom") == "6C01" || dma_resultsCopino2.get("transDstFrom") == "6P13" 
             && dma_resultsCopino2.get("transDstTo") == "6C01" || dma_resultsCopino2.get("transDstTo") == "6P13" ) {
                lc_bondTransVehclYn2.setValue(dma_resultsCopino2.get("bondTransVehclYn"));
            }
            else {
                if( dma_resultsCopino2.get("sndClsCd") != DsConstants.EDI_SND_CLS_CD_SND_COMPLETE
                 && dma_resultsCopino2.get("sndClsCd") != DsConstants.EDI_SND_CLS_CD_LATER_SND
                 && dma_resultsCopino2.get("sndClsCd") != DsConstants.EDI_SND_CLS_CD_IMPITEM_WARN
                 && dma_resultsCopino2.get("sndClsCd") != DsConstants.EDI_SND_CLS_CD_SND_WAIT ) {
                    lc_bondTransVehclYn2.setValue("N");
                 }
                 else {
                    lc_bondTransVehclYn2.setValue(dma_resultsCopino2.get("bondTransVehclYn"));
                 }
            }

            lc_frtcarClsIn.setValue(dma_resultsCopino2.get("adminfrtcarYn"));

            if( dma_resultsCopino2.get("sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_COMPLETE ) {
                div_sndClsCd2.setValue("전송완료");
            }
            else if( dma_resultsCopino2.get("sndClsCd") == DsConstants.EDI_SND_CLS_CD_LATER_SND ) {
                div_sndClsCd2.setValue("사후전송");
            }
            else if( dma_resultsCopino2.get("sndClsCd") == DsConstants.EDI_SND_CLS_CD_IMPITEM_WARN ) {
                div_sndClsCd2.setValue("필수입력오류");
            }
            else if( dma_resultsCopino2.get("sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_WAIT ) {
                div_sndClsCd2.setValue("전송대기");
            }
            else {
                div_sndClsCd2.setValue("미등록");
            }

            if( dma_resultsCopino2.get("preInfoGrpClsCd") == DsConstants.EDI_GRPCD_KYUNGIN_ICD
             && dma_resultsCopino2.get("wrkStpCd") != DsConstants.WRK_STP_CD_RAILROAD ) {
                $c.gus.cfDisableObjects([em_vehclNoFrtcarNo2]);
            }

            if( dma_resultsCopino2.get("copinoResponse") == "" ) {
                lbl_copinoErr2.setValue("");
            }
            else {
                var tempStr = "<font color=blue>반입 COPINO 전송오류 내역 :</font> "
                            + "<font color=red>" + dma_resultsCopino2.get("copinoResponse") + "</font><br>";

                lbl_copinoErr2.setValue(tempStr);
            }
        }
    }

    if (v_bIsCrryOut) {
        $c.gus.cfEnableObjects([tb_crryOutCopino, chk_crryOutCopino]);
        chk_crryOutCopino.click(0); //true
        txa_reason1.setReadOnly(true);
    }
    else {
        chk_crryOutCopino.setValue("F");
        $c.gus.cfDisableObjects([tb_crryOutCopino, chk_crryOutCopino]);
        //chk_crryOutCopino.set = false
    }

    if (v_bIsCrryIn) {
        $c.gus.cfEnableObjects([tb_crryInCopino, chk_crryInCopino]);
        chk_crryInCopino.click(0); //true
        txa_reason2.setReadOnly(true);
    }
    else {
        chk_crryInCopino.setValue("F");
        $c.gus.cfDisableObjects([tb_crryInCopino, chk_crryInCopino]);
        //chk_crryInCopino.set = false
    }

    //황창기 자가업체 보세운송차량여부 수정 불가하게 수정			  
	if(scwin.userClsCd == "05"){
		$c.gus.cfDisableObjects([lc_bondTransVehclYn1, lc_bondTransVehclYn2]);
	}

    if( !(ds_resultsCopino.getCellData(0, "transDstFrom") == "4R01" 
        || ds_resultsCopino.getCellData(0, "transDstFrom") == "4C02" 
        || ds_resultsCopino.getCellData(0, "transDstFrom") == "4C03")     
       ){
        $c.gus.cfDisableObjects([tb_kiIcdOut]);
    }

    if( !(ds_resultsCopino.getCellData(0, "transDstTo") == "4R01" 
        || ds_resultsCopino.getCellData(0, "transDstTo") == "4C02" 
        || ds_resultsCopino.getCellData(0, "transDstTo") == "4C03")       
       ){
        $c.gus.cfDisableObjects([tb_kiIcdIn]);
    }

    if( !(ds_resultsCopino.getCellData(0, "transDstFrom") == "6P10" 
        || ds_resultsCopino.getCellData(0, "transDstFrom") == "6C09")     
       ){
        $c.gus.cfDisableObjects([tb_dpctOut]);
    }

    if( !(ds_resultsCopino.getCellData(0, "transDstTo") == "6P10" 
        || ds_resultsCopino.getCellData(0, "transDstTo") == "6C09")       
       ){
        $c.gus.cfDisableObjects([tb_dpctIn]);
    }

    //인천대한통운전용은 사용자 점소가 인천지사, 작업장이 대통4부두(4P15), 대통남항(4P14)경우만 보인다. - 이승희 대리 요청 2014.11.27
    if( DsConstants.WRK_LOBRAN_CD_INCHON == scwin.loUpperLobranCd
        || (ds_resultsCopino.getCellData(0, "transDstFrom") == "4P15" || ds_resultsCopino.getCellData(0, "transDstFrom") == "4P14" )
        || (ds_resultsCopino.getCellData(0, "transDstTo") == "4P15" || ds_resultsCopino.getCellData(0, "transDstTo") == "4P14") ) {

        tb_dtOut.show();
        tb_dtIn.show();
    }
    else {
        tb_dtOut.hide();
        tb_dtIn.hide();
    }

    if( scwin.param_gubun == "NO" ) {
    	$c.gus.cfDisableObjects([em_cntrNo2,em_cntrNo]); 
    }
};

scwin.ds_resultsCopiCodeco_ondataload = function () {
    console.log("#### ds_resultsCopiCodeco_ondataload : "+ds_resultsCopiCodeco.getRowCount());

    dma_resultsCopiCodeco1.setEmptyValue();
    dma_resultsCopiCodeco2.setEmptyValue();

    var v_bIsCrryOut = false;
    var v_bIsCrryIn  = false;

    for( var i = 0; i <= ds_resultsCopiCodeco.getRowCount(); i++ ) {

        if( ds_resultsCopiCodeco.getCellData(i, "crryinCrryoutCls") == "1" ) {
            v_bIsCrryOut = true;
        }

        if( ds_resultsCopiCodeco.getCellData(i, "crryinCrryoutCls") == "2" ) {
            v_bIsCrryIn = true;
        }

        if( ds_resultsCopiCodeco.getCellData(i, "crryinCrryoutCls") == "1" ) {
            //반출
            dma_resultsCopiCodeco1.setJSON(ds_resultsCopiCodeco.getRowJSON(i));

            if( dma_resultsCopiCodeco1.get("cls") == "HY" ) {
                td_cls3.setValue("현대용당(HY)");  //구분
            }
            else if( dma_resultsCopiCodeco1.get("cls") == "DT" ) {
                td_cls3.setValue("대한통운(DT)");  //구분
            }
            else {
                td_cls3.setValue("현대경인(HK)");  //구분
            }

            td_wrkPlCd3.setValue(txt_dptWrkPlNm.getValue());  //작업지역

            if( dma_resultsCopiCodeco1.get("cls") == "DT" ) {
                em_blNo31.setValue(dma_resultsCopiCodeco1.get("blNo"));  //화물관리번호
            }
            else {
                em_blNo3.setValue(dma_resultsCopiCodeco1.get("blNo"));  //B/L NO
            }

            if( dma_resultsCopiCodeco1.get("sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_COMPLETE ) {
                div_sndClsCd3.setValue("전송완료");
            }
            else if( dma_resultsCopiCodeco1.get("sndClsCd") == DsConstants.EDI_SND_CLS_CD_LATER_SND ) {
                div_sndClsCd3.setValue("사후전송");
            }
            else if( dma_resultsCopiCodeco1.get("sndClsCd") == DsConstants.EDI_SND_CLS_CD_IMPITEM_WARN ) {
                div_sndClsCd3.setValue("필수입력오류");
            }
            else if( dma_resultsCopiCodeco1.get("sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_WAIT ) {
                div_sndClsCd3.setValue("전송대기");
            }
            else {
                div_sndClsCd3.setValue("미등록");
            }
        }

        if( ds_resultsCopiCodeco.getCellData(i, "crryinCrryoutCls") == "2" ) {
            //반입
            dma_resultsCopiCodeco2.setJSON(ds_resultsCopiCodeco.getRowJSON(i));

            if( dma_resultsCopiCodeco2.get("cls") == "HY" ) {
                td_cls4.setValue("현대용당(HY)");  //구분
            }
            else if( dma_resultsCopiCodeco2.get("cls") == "DT" ) {
                td_cls4.setValue("대한통운(DT)");  //구분
            }
            else {
                td_cls4.setValue("현대경인(HK)");  //구분
            }

            td_wrkPlCd4.setValue(txt_dptWrkPlNm.getValue());  //작업지역

            if( dma_resultsCopiCodeco2.get("cls") == "DT" ) {
                em_blNo41.setValue(dma_resultsCopiCodeco2.get("blNo"));  //화물관리번호
            }
            else {
                em_blNo4.setValue(dma_resultsCopiCodeco2.get("blNo"));  //B/L NO
            }

            if( dma_resultsCopiCodeco2.get("sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_COMPLETE ) {
                div_sndClsCd4.setValue("전송완료");
            }
            else if( dma_resultsCopiCodeco2.get("sndClsCd") == DsConstants.EDI_SND_CLS_CD_LATER_SND ) {
                div_sndClsCd4.setValue("사후전송");
            }
            else if( dma_resultsCopiCodeco2.get("sndClsCd") == DsConstants.EDI_SND_CLS_CD_IMPITEM_WARN ) {
                div_sndClsCd4.setValue("필수입력오류");
            }
            else if( dma_resultsCopiCodeco2.get("sndClsCd") == DsConstants.EDI_SND_CLS_CD_SND_WAIT ) {
                div_sndClsCd4.setValue("전송대기");
            }
            else {
                div_sndClsCd4.setValue("미등록");
            }
        }
    }

    if (v_bIsCrryOut) {
        $c.gus.cfEnableObjects([tb_crryOutCopiCodeco, chk_crryOutCopiCodeco]);
        scwin.f_disableCompCopiCodeco(dma_resultsCopiCodeco1.get("cls"), 1);
        chk_crryOutCopiCodeco.click(0);  //true
        txa_reason3.setReadOnly(true);
    }
    else {
        chk_crryOutCopiCodeco.setValue("F");
        $c.gus.cfDisableObjects([tb_crryOutCopiCodeco, chk_crryOutCopiCodeco]);
        //chk_crryOutCopiCodeco.click(index);  //false
    }

    if (v_bIsCrryIn) {
        $c.gus.cfEnableObjects([tb_crryInCopiCodeco, chk_crryInCopiCodeco]);
        scwin.f_disableCompCopiCodeco(dma_resultsCopiCodeco2.get("cls"), 2);
        chk_crryInCopiCodeco.click(0);  //true
        txa_reason4.setReadOnly(true);
    }
    else {
        chk_crryInCopiCodeco.setValue("F");
        $c.gus.cfDisableObjects([tb_crryInCopiCodeco, chk_crryInCopiCodeco]);
        //chk_crryInCopiCodeco.checked = false;
    }
};

scwin.select_delimiter = function(tmpVal) {
    let value = this.itemArr[this.getSelectedIndex()].value;
    let label = this.itemArr[this.getSelectedIndex()].orgLabel;
    return "["+ value +"] " + label;
};

