                                        ,null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                                        ,null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                                        ,null                   // 윈도우 위치 Y좌표   
                                        ,null                   // 윈도우 위치 X좌표
                                        ,null                   // 중복체크여부   ("F")
                                        ,pAllSearch             // 전체검색허용여부 ("F")
                                        ,null                   // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                        );
            }

            break; 

        case 13://황창기 보세장치장 조회 팝업추가
            pTitle = "보세장치장,장치장코드,장치장명";
            rtnList = udc_bondYardCd.cfCommonPopUp(scwin.udc_bondYardCd_callBackFunc	// XML상의 SELECT ID	
                                    ,pCode			// 화면에서의 ??? Code Element의	Value
                                    ,pName			// 화면에서의 ??? Name Element의	Value
                                    ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                    ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null					// Title순서	
                                    ,null					// 보여주는 각 컬럼들의 폭	
                                    ,null					// 컬럼중에서 숨기는	컬럼 지정	
                                    ,pWhere					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                                    ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                                    ,null					// 윈도우 위치 Y좌표	
                                    ,null					// 윈도우 위치 X좌표
                                    ,null					// 중복체크여부	("F")
                                    ,pAllSearch				// 전체검색허용여부	("F")
                                    ,pTitle					// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                    );
            break;
        default :
            break;
    }

}

//-------------------------------------------------------------------------
// COPI_CODECO에서 사용할 화주 팝업
//-------------------------------------------------------------------------
scwin.f_openBilgMchtListPopUp = async function(pCode, pName, gubun) {

    if(gubun == 1) {
        pName.setValue("");
    } else if(gubun == 2) {
        pCode.setValue("");
    }

    udc_mchtCd3.setSelectId("retrieveBilgMchtList");

    //[반출, 출발작업장의 사전정보그룹구분코드 = LG] 이면 거래처팝업 사용
    //매번 서버에 호출하게 되면 오래걸리므로 사전에 조회했던 값이 있으면 그걸 반환하고 아니면 서버에 호출하여 값을 받아오도록 한다.
	return await new Promise(function (resolve) {
        udc_mchtCd3.cfCommonPopUp(
                                function(rtnList) {
                                    if (rtnList != "") {
                                        $c.gus.cfSetReturnValue(rtnList, pCode, pName);
                                        resolve(true);
                                    } else {
                                        resolve(false);
                                    }
                                }  // CallBack Function
                                ,pCode.getValue().trim()          // 화면에서의 ??? Code Element의  Value
                                ,pName.getValue().trim()             // 화면에서의 ??? Name Element의  Value
                                ,'T'                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                                ,null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                                ,null                   // Title순서  
                                ,null                   // 보여주는 각 컬럼들의 폭    
                                ,null                   // 컬럼중에서 숨기는    컬럼 지정   
                                ,null                   // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                ,null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                                ,null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                                ,null                   // 윈도우 위치 Y좌표   
                                ,null                   // 윈도우 위치 X좌표
                                ,null                   // 중복체크여부   ("F")
                                ,null                   // 전체검색허용여부 ("F")
                                ,null                   // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
        );
    });
}

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {

    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {

        // inObj가 코드명 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
}

