scwin.em_vehclNoFull1_onblur = function (e) {

    if ( !$c.gus.cfValidate([em_vehclNoFull1]) ) {
        em_vehclNoFull2.Text = "";
    }

    //[사전정보그룹구분코드=경인ICD and 작업단계코드<>철송]
    if ( dma_resultsCopino1.get("preInfoGrpClsCd") == DsConstants.EDI_GRPCD_KYUNGIN_ICD
            && dma_resultsCopino1.get("wrkStpCd") != DsConstants.WRK_STP_CD_RAILROAD
            && dma_resultsCopino1.get("wrkStpCd") != em_vehclNoFull1.getValue() ) 
    {
        $c.gus.cfEnableObjects([em_vehclNoFrtcarNo1]);

    }
};

scwin.em_vehclNoFull2_onblur = function (e) {

